@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h2 class="mb-3">Project Board</h2>

@if (_loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_errorMessage
        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="LoadTasksAsync">Retry</button>
    </div>
}
else
{
    <!-- Stats Bar -->
    <div class="row g-2 mb-3">
        <div class="col">
            <div class="card text-center">
                <div class="card-body py-2">
                    <div class="fw-bold">@_allTasks.Count</div>
                    <small class="text-muted">Total</small>
                </div>
            </div>
        </div>
        @foreach (var col in _columns)
        {
            <div class="col">
                <div class="card text-center">
                    <div class="card-body py-2">
                        <div class="fw-bold">@GetTasksForColumn(col).Count</div>
                        <small class="text-muted">@col</small>
                    </div>
                </div>
            </div>
        }
        <div class="col">
            <div class="card text-center border-danger">
                <div class="card-body py-2">
                    <div class="fw-bold text-danger">@_allTasks.Count(t => t.DueDate < DateTime.Today)</div>
                    <small class="text-muted">Overdue</small>
                </div>
            </div>
        </div>
    </div>

    <!-- Search Bar -->
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Search tasks by title..."
               @bind="_searchText" @bind:event="oninput" />
    </div>

    <!-- Kanban Columns -->
    <div class="row g-3">
        @for (var i = 0; i < _columns.Length; i++)
        {
            var colIndex = i;
            var colName = _columns[colIndex];
            var tasks = GetFilteredTasksForColumn(colName);

            <div class="col-md-4">
                <div class="card h-100">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>@colName</strong>
                        <span class="badge bg-secondary">@tasks.Count</span>
                    </div>
                    <div class="card-body d-flex flex-column gap-2" style="min-height: 200px;">
                        @foreach (var task in tasks)
                        {
                            <div class="card shadow-sm">
                                <div class="card-body p-2">
                                    <div class="fw-semibold mb-1">@task.Title</div>
                                    <div class="d-flex align-items-center gap-2 mb-1">
                                        <small class="text-muted">@task.Assignee</small>
                                        <span class="badge @GetPriorityClass(task.Priority)">@task.Priority</span>
                                    </div>
                                    <div class="d-flex justify-content-between align-items-center">
                                        <small class="text-muted">@task.DueDate.ToString("MMM dd")</small>
                                        <div class="btn-group btn-group-sm">
                                            @if (colIndex > 0)
                                            {
                                                var leftStatus = _columns[colIndex - 1];
                                                <button class="btn btn-outline-secondary btn-sm"
                                                        @onclick="() => MoveTaskAsync(task.Id, leftStatus)">
                                                    &laquo; Move Left
                                                </button>
                                            }
                                            @if (colIndex < _columns.Length - 1)
                                            {
                                                var rightStatus = _columns[colIndex + 1];
                                                <button class="btn btn-outline-secondary btn-sm"
                                                        @onclick="() => MoveTaskAsync(task.Id, rightStatus)">
                                                    Move Right &raquo;
                                                </button>
                                            }
                                        </div>
                                    </div>
                                </div>
                            </div>
                        }

                        @if (_addingToColumn == colName)
                        {
                            <div class="card border-primary mt-auto">
                                <div class="card-body p-2">
                                    <div class="mb-2">
                                        <input type="text" class="form-control form-control-sm" placeholder="Title"
                                               @bind="_newTitle" />
                                    </div>
                                    <div class="mb-2">
                                        <input type="text" class="form-control form-control-sm" placeholder="Assignee"
                                               @bind="_newAssignee" />
                                    </div>
                                    <div class="mb-2">
                                        <select class="form-select form-select-sm" @bind="_newPriority">
                                            <option value="High">High</option>
                                            <option value="Medium">Medium</option>
                                            <option value="Low">Low</option>
                                        </select>
                                    </div>
                                    <div class="mb-2">
                                        <input type="date" class="form-control form-control-sm"
                                               @bind="_newDueDate" />
                                    </div>
                                    <div class="d-flex gap-2">
                                        <button class="btn btn-primary btn-sm" @onclick="SaveNewTaskAsync">Save</button>
                                        <button class="btn btn-secondary btn-sm" @onclick="CancelAdd">Cancel</button>
                                    </div>
                                </div>
                            </div>
                        }
                        else
                        {
                            <button class="btn btn-outline-primary btn-sm mt-auto"
                                    @onclick="() => StartAdd(colName)">
                                + Add Task
                            </button>
                        }
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private readonly string[] _columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> _allTasks = new();
    private bool _loading = true;
    private string? _errorMessage;
    private string _searchText = string.Empty;

    // New task form state
    private string? _addingToColumn;
    private string _newTitle = string.Empty;
    private string _newAssignee = string.Empty;
    private string _newPriority = "Medium";
    private DateTime _newDueDate = DateTime.Today.AddDays(7);

    protected override async Task OnInitializedAsync()
    {
        await LoadTasksAsync();
    }

    private async Task LoadTasksAsync()
    {
        try
        {
            _loading = true;
            _errorMessage = null;
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _errorMessage = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private List<TaskItem> GetTasksForColumn(string status) =>
        _allTasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> GetFilteredTasksForColumn(string status) =>
        _allTasks
            .Where(t => t.Status == status)
            .Where(t => string.IsNullOrWhiteSpace(_searchText)
                || t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase))
            .ToList();

    private static string GetPriorityClass(string priority) => priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var idx = _allTasks.FindIndex(t => t.Id == taskId);
            if (idx >= 0)
            {
                var old = _allTasks[idx];
                _allTasks[idx] = old with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            _errorMessage = ex.Message;
        }
    }

    private void StartAdd(string column)
    {
        _addingToColumn = column;
        _newTitle = string.Empty;
        _newAssignee = string.Empty;
        _newPriority = "Medium";
        _newDueDate = DateTime.Today.AddDays(7);
    }

    private void CancelAdd()
    {
        _addingToColumn = null;
    }

    private async Task SaveNewTaskAsync()
    {
        if (string.IsNullOrWhiteSpace(_newTitle) || _addingToColumn is null)
            return;

        try
        {
            var created = await TaskService.CreateTaskAsync(_newTitle, _newAssignee, _newPriority, _newDueDate);
            // The service creates with a default status; update to the target column if different
            if (created.Status != _addingToColumn)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, _addingToColumn);
                created = created with { Status = _addingToColumn };
            }
            _allTasks.Add(created);
            _addingToColumn = null;
        }
        catch (Exception ex)
        {
            _errorMessage = ex.Message;
        }
    }
}

